def count_politician_names(articles, politician_names):  
    counts = {}  
    for article in articles:  
        # remove punctuation and convert to lowercase  
        cleaned_article = article.lower().replace(",", "").replace(".", "").replace("!", "")  
        # split into words  
        words = cleaned_article.split()  
        # check for politician names  
        for word in words:  
            if word in politician_names:  
                counts[word] = counts.get(word, 0) + 1  
    return counts  

